-- ----------------------------------------------------------------------------
-- Workflows: Table: Workflows. The NTWF Workflow class — prov:Plan + schema:CreativeWork. Each workflow has Dublin Core metadata (title, description, identifier, created, modified), a lifecycle status from the SKOS scheme, and a collection of WorkflowSteps (ntwf:hasStep).
-- ----------------------------------------------------------------------------
CREATE TABLE workflows (
  workflow_id                         TEXT                 PRIMARY KEY,
  display_name                        TEXT                ,
  title                               TEXT                ,                     -- Human-readable title of the workflow. Maps to dct:title from Dublin Core. Example: 'Production Deployment Workflow'.
  description                         TEXT                ,                     -- Detailed description of the workflow's purpose and scope. Maps to dct:description from Dublin Core. Should explain what business goal the workflow achieves.
  identifier                          TEXT                ,                     -- External system identifier for cross-referencing. Maps to dct:identifier from Dublin Core. This is the join key back to document management systems, ticket systems, or other operational systems.
  modified                            TIMESTAMPTZ         ,                     -- Last modification timestamp. Maps to dct:modified from Dublin Core. Critical for answering CQ5: 'Which workflows haven't been reviewed or updated in twelve months?'
  created                             TIMESTAMPTZ         ,                     -- Creation timestamp. Maps to dct:created from Dublin Core. Records when the workflow was first defined.
  staleness_threshold_months          INTEGER             ,                     -- The governance POLICY (in months): the full review cadence after which this workflow's compliance documentation is formally out of date. The docs go stale exactly when this review age is exceeded — IsStale fires the instant MonthsSinceModified passes this policy line, with no deferral. The article hardcodes the CQ5 question at twelve months ('which workflows haven't been reviewed in twelve months'); promoting that threshold to a raw, editable field makes the policy itself a fact in the SSoT rather than a constant buried in the IsStale formula — so an org can set a 6-month or 18-month review cadence and the staleness verdict recomputes. Defaults to 12 to match the article.
  workflow_status                     TEXT                ,                     -- FK to WorkflowStatusConcepts. Captures the current lifecycle state of the workflow (draft, active, deprecated, archived). Maps to the SKOS CBox status vocabulary.
  workflow_steps                      TEXT                                      -- Reference to workflow steps. Represents the ntwf:hasStep relationship linking workflows to their constituent steps.
);
COMMENT ON TABLE workflows IS 'Table: Workflows. The NTWF Workflow class — prov:Plan + schema:CreativeWork. Each workflow has Dublin Core metadata (title, description, identifier, created, modified), a lifecycle status from the SKOS scheme, and a collection of WorkflowSteps (ntwf:hasStep).';
COMMENT ON COLUMN workflows.title IS 'Human-readable title of the workflow. Maps to dct:title from Dublin Core. Example: ''Production Deployment Workflow''.';
COMMENT ON COLUMN workflows.description IS 'Detailed description of the workflow''s purpose and scope. Maps to dct:description from Dublin Core. Should explain what business goal the workflow achieves.';
COMMENT ON COLUMN workflows.identifier IS 'External system identifier for cross-referencing. Maps to dct:identifier from Dublin Core. This is the join key back to document management systems, ticket systems, or other operational systems.';
COMMENT ON COLUMN workflows.modified IS 'Last modification timestamp. Maps to dct:modified from Dublin Core. Critical for answering CQ5: ''Which workflows haven''t been reviewed or updated in twelve months?''';
COMMENT ON COLUMN workflows.created IS 'Creation timestamp. Maps to dct:created from Dublin Core. Records when the workflow was first defined.';
COMMENT ON COLUMN workflows.staleness_threshold_months IS 'The governance POLICY (in months): the full review cadence after which this workflow''s compliance documentation is formally out of date. The docs go stale exactly when this review age is exceeded — IsStale fires the instant MonthsSinceModified passes this policy line, with no deferral. The article hardcodes the CQ5 question at twelve months (''which workflows haven''t been reviewed in twelve months''); promoting that threshold to a raw, editable field makes the policy itself a fact in the SSoT rather than a constant buried in the IsStale formula — so an org can set a 6-month or 18-month review cadence and the staleness verdict recomputes. Defaults to 12 to match the article.';
COMMENT ON COLUMN workflows.workflow_status IS 'FK to WorkflowStatusConcepts. Captures the current lifecycle state of the workflow (draft, active, deprecated, archived). Maps to the SKOS CBox status vocabulary.';
COMMENT ON COLUMN workflows.workflow_steps IS 'Reference to workflow steps. Represents the ntwf:hasStep relationship linking workflows to their constituent steps.';

-- ----------------------------------------------------------------------------
-- WorkflowSteps: Table: WorkflowSteps. The NTWF WorkflowStep class — prov:Activity. Each step is first-class and individually addressable, belongs to one Workflow (ntwf:isStepOf), and is assigned to exactly one Role (ntwf:assignedRole). Step-to-step ordering is modeled in the StepPrecedence junction; the ApprovalGate subtype specializes a step via a 1:1 FK.
-- ----------------------------------------------------------------------------
CREATE TABLE workflow_steps (
  workflow_step_id                    TEXT                 PRIMARY KEY,
  display_name                        TEXT                ,
  workflow                            TEXT                ,                     -- Foreign key to the parent workflow. Represents the inverse of ntwf:hasStep, enabling navigation from step to its containing workflow (ntwf:isStepOf).
  sequence_position_override          INTEGER             ,                     -- OPTIONAL hand-asserted ordinal position — the article's pure ntwf:sequencePosition functional datatype property, preserved as an override slot. NULL on the linear Production Deployment chain (the inference is unambiguous, so nothing is pinned). When set, it wins over InferredSequencePosition in the resolved SequencePosition — this is how a modeler recovers the owl:FunctionalProperty 'exactly one distinct position per step' guarantee on a partial order / branch where the inferred rank would tie. Maps to ntwf:sequencePosition (the article's asserted functional property).
  assigned_role                       TEXT                ,                     -- Foreign key to the Role responsible for executing this step. Maps to ntwf:assignedRole (owl:FunctionalProperty — exactly one role per step). Critical for implementing Heuristic 2 (role-agent separation): steps point to roles, not directly to agents.
  requires_human_approval             BOOLEAN             ,                     -- Boolean flag indicating whether a human agent must fill the assigned role. Maps to ntwf:requiresHumanApproval. Enables answering CQ3: 'Which steps require human decisions vs. AI execution?'
  step_duration_minutes               INTEGER             ,                     -- Expected duration of this step in minutes. Maps to ntwf:stepDurationMinutes (datatype property, not functional). Enables SLA and throughput analysis.
  consumes_dataset                    TEXT                ,                     -- FK to Datasets. Records which DCAT dataset this step consumes as input. Kept separate from artifact consumption to preserve DCAT metadata semantics (consumesDataset vs. requiresArtifact).
  produces_artifacts                  TEXT                ,                     -- Back-reference to WorkflowArtifacts produced by this step. Inverse of WorkflowArtifacts.ProducedByStep (ntwf:producesArtifact / prov:wasGeneratedBy).
  requires_artifacts                  TEXT                ,                     -- FK to WorkflowArtifact(s) this step CONSUMES as input. Maps to ntwf:requiresArtifact (aligned to prov:used). Kept distinct from producesArtifact (prov:generated) and from consumesDataset (dcat:Dataset) so the input/output and artifact/dataset semantics stay separate. Inverse is WorkflowArtifacts.RequiredBySteps.
  approval_gate                       TEXT                ,                     -- Back-reference to the ApprovalGate subtype row that specializes this step, if any. Inverse of ApprovalGates.WorkflowStep. A step has zero or one approval gate; when present, the gate adds escalationThresholdHours and marks the step as a blocking decision checkpoint. This models ntwf:ApprovalGate rdfs:subClassOf WorkflowStep as a shared-key 1:1 specialization rather than collapsing two DAG nodes into one.
  precedes                            TEXT                ,                     -- Back-reference to StepPrecedence edges where this step is the FromStep (the predecessor). Inverse of StepPrecedence.FromStep. Together with PrecededBy, lets you walk the ntwf:precedesStep ordering in both directions.
  preceded_by                         TEXT                                      -- Back-reference to StepPrecedence edges where this step is the ToStep (the successor). Inverse of StepPrecedence.ToStep. Part of the ntwf:precedesStep transitive ordering relationship.
);
COMMENT ON TABLE workflow_steps IS 'Table: WorkflowSteps. The NTWF WorkflowStep class — prov:Activity. Each step is first-class and individually addressable, belongs to one Workflow (ntwf:isStepOf), and is assigned to exactly one Role (ntwf:assignedRole). Step-to-step ordering is modeled in the StepPrecedence junction; the ApprovalGate subtype specializes a step via a 1:1 FK.';
COMMENT ON COLUMN workflow_steps.workflow IS 'Foreign key to the parent workflow. Represents the inverse of ntwf:hasStep, enabling navigation from step to its containing workflow (ntwf:isStepOf).';
COMMENT ON COLUMN workflow_steps.sequence_position_override IS 'OPTIONAL hand-asserted ordinal position — the article''s pure ntwf:sequencePosition functional datatype property, preserved as an override slot. NULL on the linear Production Deployment chain (the inference is unambiguous, so nothing is pinned). When set, it wins over InferredSequencePosition in the resolved SequencePosition — this is how a modeler recovers the owl:FunctionalProperty ''exactly one distinct position per step'' guarantee on a partial order / branch where the inferred rank would tie. Maps to ntwf:sequencePosition (the article''s asserted functional property).';
COMMENT ON COLUMN workflow_steps.assigned_role IS 'Foreign key to the Role responsible for executing this step. Maps to ntwf:assignedRole (owl:FunctionalProperty — exactly one role per step). Critical for implementing Heuristic 2 (role-agent separation): steps point to roles, not directly to agents.';
COMMENT ON COLUMN workflow_steps.requires_human_approval IS 'Boolean flag indicating whether a human agent must fill the assigned role. Maps to ntwf:requiresHumanApproval. Enables answering CQ3: ''Which steps require human decisions vs. AI execution?''';
COMMENT ON COLUMN workflow_steps.step_duration_minutes IS 'Expected duration of this step in minutes. Maps to ntwf:stepDurationMinutes (datatype property, not functional). Enables SLA and throughput analysis.';
COMMENT ON COLUMN workflow_steps.consumes_dataset IS 'FK to Datasets. Records which DCAT dataset this step consumes as input. Kept separate from artifact consumption to preserve DCAT metadata semantics (consumesDataset vs. requiresArtifact).';
COMMENT ON COLUMN workflow_steps.produces_artifacts IS 'Back-reference to WorkflowArtifacts produced by this step. Inverse of WorkflowArtifacts.ProducedByStep (ntwf:producesArtifact / prov:wasGeneratedBy).';
COMMENT ON COLUMN workflow_steps.requires_artifacts IS 'FK to WorkflowArtifact(s) this step CONSUMES as input. Maps to ntwf:requiresArtifact (aligned to prov:used). Kept distinct from producesArtifact (prov:generated) and from consumesDataset (dcat:Dataset) so the input/output and artifact/dataset semantics stay separate. Inverse is WorkflowArtifacts.RequiredBySteps.';
COMMENT ON COLUMN workflow_steps.approval_gate IS 'Back-reference to the ApprovalGate subtype row that specializes this step, if any. Inverse of ApprovalGates.WorkflowStep. A step has zero or one approval gate; when present, the gate adds escalationThresholdHours and marks the step as a blocking decision checkpoint. This models ntwf:ApprovalGate rdfs:subClassOf WorkflowStep as a shared-key 1:1 specialization rather than collapsing two DAG nodes into one.';
COMMENT ON COLUMN workflow_steps.precedes IS 'Back-reference to StepPrecedence edges where this step is the FromStep (the predecessor). Inverse of StepPrecedence.FromStep. Together with PrecededBy, lets you walk the ntwf:precedesStep ordering in both directions.';
COMMENT ON COLUMN workflow_steps.preceded_by IS 'Back-reference to StepPrecedence edges where this step is the ToStep (the successor). Inverse of StepPrecedence.ToStep. Part of the ntwf:precedesStep transitive ordering relationship.';

-- ----------------------------------------------------------------------------
-- ApprovalGates: Table: ApprovalGates. The NTWF ApprovalGate class — rdfs:subClassOf WorkflowStep. Modeled as a class-table-inheritance subtype: each gate row shares identity with exactly one WorkflowStep (via the WorkflowStep 1:1 FK) and carries only the gate-specific attribute, escalationThresholdHours. The step it specializes keeps the common attributes (requiresHumanApproval, assigned role, etc.). This preserves the article's double-typing — a gate IS a step — without collapsing two DAG nodes into one.
-- ----------------------------------------------------------------------------
CREATE TABLE approval_gates (
  approval_gate_id                    TEXT                 PRIMARY KEY,
  display_name                        TEXT                ,
  workflow_step                       TEXT                ,                     -- 1:1 FK to the WorkflowStep this gate specializes (subtype shared key). This is the relational expression of ntwf:ApprovalGate rdfs:subClassOf WorkflowStep: the gate row adds escalationThresholdHours to its step. Inverse is WorkflowSteps.ApprovalGate.
  escalation_threshold_hours          INTEGER                                   -- Integer number of hours that may elapse on a pending gate before the ntwf:delegatesTo chain activates. Maps to ntwf:escalationThresholdHours. Domain applies only to ApprovalGate individuals — which is exactly why the gate is its own subtype table and this attribute does not live on every WorkflowStep.
);
COMMENT ON TABLE approval_gates IS 'Table: ApprovalGates. The NTWF ApprovalGate class — rdfs:subClassOf WorkflowStep. Modeled as a class-table-inheritance subtype: each gate row shares identity with exactly one WorkflowStep (via the WorkflowStep 1:1 FK) and carries only the gate-specific attribute, escalationThresholdHours. The step it specializes keeps the common attributes (requiresHumanApproval, assigned role, etc.). This preserves the article''s double-typing — a gate IS a step — without collapsing two DAG nodes into one.';
COMMENT ON COLUMN approval_gates.workflow_step IS '1:1 FK to the WorkflowStep this gate specializes (subtype shared key). This is the relational expression of ntwf:ApprovalGate rdfs:subClassOf WorkflowStep: the gate row adds escalationThresholdHours to its step. Inverse is WorkflowSteps.ApprovalGate.';
COMMENT ON COLUMN approval_gates.escalation_threshold_hours IS 'Integer number of hours that may elapse on a pending gate before the ntwf:delegatesTo chain activates. Maps to ntwf:escalationThresholdHours. Domain applies only to ApprovalGate individuals — which is exactly why the gate is its own subtype table and this attribute does not live on every WorkflowStep.';

-- ----------------------------------------------------------------------------
-- StepPrecedence: Table: StepPrecedence. The NTWF ntwf:precedesStep ordering relationship, modeled as a first-class step-to-step junction. Each row is one directed edge: FromStep precedes ToStep. ntwf:precedesStep is an owl:TransitiveProperty — the four asserted edges (1->2, 2->3, 3->4, 4->5) imply the full closure of ten ordering pairs (including 1->5, which is never asserted). Each edge is a first-class node in the DAG, never a 'helper' integer.
-- ----------------------------------------------------------------------------
CREATE TABLE step_precedence (
  step_precedence_id                  TEXT                 PRIMARY KEY,
  from_step                           TEXT                ,                     -- FK to the predecessor WorkflowStep — the step that comes BEFORE. The source of the ntwf:precedesStep edge. Inverse is WorkflowSteps.Precedes.
  to_step                             TEXT                                      -- FK to the successor WorkflowStep — the step that comes AFTER. The target of the ntwf:precedesStep edge. Inverse is WorkflowSteps.PrecededBy.
);
COMMENT ON TABLE step_precedence IS 'Table: StepPrecedence. The NTWF ntwf:precedesStep ordering relationship, modeled as a first-class step-to-step junction. Each row is one directed edge: FromStep precedes ToStep. ntwf:precedesStep is an owl:TransitiveProperty — the four asserted edges (1->2, 2->3, 3->4, 4->5) imply the full closure of ten ordering pairs (including 1->5, which is never asserted). Each edge is a first-class node in the DAG, never a ''helper'' integer.';
COMMENT ON COLUMN step_precedence.from_step IS 'FK to the predecessor WorkflowStep — the step that comes BEFORE. The source of the ntwf:precedesStep edge. Inverse is WorkflowSteps.Precedes.';
COMMENT ON COLUMN step_precedence.to_step IS 'FK to the successor WorkflowStep — the step that comes AFTER. The target of the ntwf:precedesStep edge. Inverse is WorkflowSteps.PrecededBy.';

-- ----------------------------------------------------------------------------
-- Roles: Table: Roles. The NTWF Role class — a custom root with no adequate standard match, declared disjoint with WorkflowStep and WorkflowArtifact. Roles are the heart of Heuristic 2 (role-agent separation): WorkflowSteps point to Roles; Roles point to exactly one agent (human, AI, or pipeline) via the polymorphic filledBy relationship. When personnel or models change, one filledBy triple changes and the workflow structure is untouched.
-- ----------------------------------------------------------------------------
CREATE TABLE roles (
  role_id                             TEXT                 PRIMARY KEY,
  display_name                        TEXT                ,
  label                               TEXT                ,                     -- Human-readable display name. Maps to rdfs:label. Per Heuristic 6: if you cannot write a clear label, you do not yet understand the concept well enough to model it.
  comment                             TEXT                ,                     -- Detailed description of the role's responsibilities and scope. Maps to rdfs:comment. Should define what the role covers, what it excludes, and how it differs from adjacent roles.
  has_capability                      TEXT                ,                     -- FK to AgentCapabilityConcepts. Declares the capability this role requires of its filler. Maps to ntwf:hasCapability. Enables CQ: 'Which roles require AI-specific capabilities?'
  filled_by_human_agent               TEXT                ,                     -- One arm of the polymorphic ntwf:filledBy relationship: FK to the HumanAgent that fills this role today. Exactly one of FilledByHumanAgent / FilledByAIAgent / FilledByAutomatedPipeline is set per role (filledBy is functional; the three agent types are owl:disjointWith each other). Roles whose capability requires human judgment or legal review must use this arm.
  filled_by_ai_agent                  TEXT                ,                     -- One arm of the polymorphic ntwf:filledBy relationship: FK to the AIAgent that fills this role today. Exactly one filledBy arm is set per role. An AIAgent may fill probabilistic-capability roles (e.g. risk analysis) but never a role whose step has requiresHumanApproval.
  filled_by_automated_pipeline        TEXT                ,                     -- One arm of the polymorphic ntwf:filledBy relationship: FK to the AutomatedPipeline that fills this role today. Exactly one filledBy arm is set per role. Pipelines fill deterministic execution roles (e.g. CI/CD).
  owned_by                            TEXT                ,                     -- Foreign key to the Department that owns this role. Maps to ntwf:ownedBy (owl:FunctionalProperty). Enables answering CQ7: 'Which workflows involve both Engineering and Legal?'
  delegates_to                        TEXT                ,                     -- Foreign key to the next Role in the escalation chain. Maps to ntwf:delegatesTo (traversable via the SPARQL property path delegatesTo+). Enables answering CQ6: 'What happens when the Release Manager / VP of Engineering is unavailable?'
  workflow_steps                      TEXT                ,                     -- Back-reference to workflow steps assigned to this role. Inverse of WorkflowSteps.AssignedRole.
  from_delegates_to                   TEXT                ,                     -- Back-reference: the Role that delegates TO this role (one step up the escalation chain). Inverse of Roles.DelegatesTo.
  role_assignments                    TEXT                                      -- Back-reference to the temporal filledBy history for this role (every validity period, current and retained). Inverse of RoleAssignments.Role.
);
COMMENT ON TABLE roles IS 'Table: Roles. The NTWF Role class — a custom root with no adequate standard match, declared disjoint with WorkflowStep and WorkflowArtifact. Roles are the heart of Heuristic 2 (role-agent separation): WorkflowSteps point to Roles; Roles point to exactly one agent (human, AI, or pipeline) via the polymorphic filledBy relationship. When personnel or models change, one filledBy triple changes and the workflow structure is untouched.';
COMMENT ON COLUMN roles.label IS 'Human-readable display name. Maps to rdfs:label. Per Heuristic 6: if you cannot write a clear label, you do not yet understand the concept well enough to model it.';
COMMENT ON COLUMN roles.comment IS 'Detailed description of the role''s responsibilities and scope. Maps to rdfs:comment. Should define what the role covers, what it excludes, and how it differs from adjacent roles.';
COMMENT ON COLUMN roles.has_capability IS 'FK to AgentCapabilityConcepts. Declares the capability this role requires of its filler. Maps to ntwf:hasCapability. Enables CQ: ''Which roles require AI-specific capabilities?''';
COMMENT ON COLUMN roles.filled_by_human_agent IS 'One arm of the polymorphic ntwf:filledBy relationship: FK to the HumanAgent that fills this role today. Exactly one of FilledByHumanAgent / FilledByAIAgent / FilledByAutomatedPipeline is set per role (filledBy is functional; the three agent types are owl:disjointWith each other). Roles whose capability requires human judgment or legal review must use this arm.';
COMMENT ON COLUMN roles.filled_by_ai_agent IS 'One arm of the polymorphic ntwf:filledBy relationship: FK to the AIAgent that fills this role today. Exactly one filledBy arm is set per role. An AIAgent may fill probabilistic-capability roles (e.g. risk analysis) but never a role whose step has requiresHumanApproval.';
COMMENT ON COLUMN roles.filled_by_automated_pipeline IS 'One arm of the polymorphic ntwf:filledBy relationship: FK to the AutomatedPipeline that fills this role today. Exactly one filledBy arm is set per role. Pipelines fill deterministic execution roles (e.g. CI/CD).';
COMMENT ON COLUMN roles.owned_by IS 'Foreign key to the Department that owns this role. Maps to ntwf:ownedBy (owl:FunctionalProperty). Enables answering CQ7: ''Which workflows involve both Engineering and Legal?''';
COMMENT ON COLUMN roles.delegates_to IS 'Foreign key to the next Role in the escalation chain. Maps to ntwf:delegatesTo (traversable via the SPARQL property path delegatesTo+). Enables answering CQ6: ''What happens when the Release Manager / VP of Engineering is unavailable?''';
COMMENT ON COLUMN roles.workflow_steps IS 'Back-reference to workflow steps assigned to this role. Inverse of WorkflowSteps.AssignedRole.';
COMMENT ON COLUMN roles.from_delegates_to IS 'Back-reference: the Role that delegates TO this role (one step up the escalation chain). Inverse of Roles.DelegatesTo.';
COMMENT ON COLUMN roles.role_assignments IS 'Back-reference to the temporal filledBy history for this role (every validity period, current and retained). Inverse of RoleAssignments.Role.';

-- ----------------------------------------------------------------------------
-- RoleAssignments: Table: RoleAssignments. The temporal history of ntwf:filledBy. NTWF's change-management discipline requires that when a filledBy triple is updated the old triple is NOT deleted — it is timestamped and retained, or replaced with a versioned triple carrying a validity period. Each row is one filledBy binding with a ValidFrom / ValidTo validity period and the reason for the change, so that 'which agent was executing this step on March 1, 2026?' is answerable from the graph. The current binding on Roles.FilledBy* is the row whose ValidTo is blank (IsCurrent = TRUE); closed rows preserve provenance and chain of custody. This is the relational equivalent of the ontology's named-graph / versioned-triple retention practice.
-- ----------------------------------------------------------------------------
CREATE TABLE role_assignments (
  role_assignment_id                  TEXT                 PRIMARY KEY,
  role                                TEXT                ,                     -- FK to the Role this assignment binds an agent to. The subject of the historical ntwf:filledBy triple.
  filled_by_human_agent               TEXT                ,                     -- One arm of the polymorphic filledBy binding for this assignment period: FK to the HumanAgent who filled the role during this window. Exactly one filler arm is set per assignment.
  filled_by_ai_agent                  TEXT                ,                     -- One arm of the polymorphic filledBy binding: FK to the AIAgent who filled the role during this window. Exactly one filler arm is set per assignment.
  filled_by_automated_pipeline        TEXT                ,                     -- One arm of the polymorphic filledBy binding: FK to the AutomatedPipeline that filled the role during this window. Exactly one filler arm is set per assignment.
  valid_from                          DATE                ,                     -- Start of the validity period for this filledBy binding (inclusive). A retained/versioned triple carries the validity period. ISO date.
  valid_to                            DATE                ,                     -- End of the validity period for this filledBy binding (exclusive). Blank means the binding is still current — this is the live ntwf:filledBy value mirrored on Roles. A non-blank value means the binding was superseded; the row is retained (not deleted) to preserve provenance.
  reason                              TEXT                ,                     -- The WHY of the change: the audit record must reflect when that transition happened and why. e.g. 'initial assignment', 'departure / backfill', 'model upgrade', 'compliance reassignment to human'.
  prior_filler_type                   TEXT                                      -- The agent class (HumanAgent / AIAgent / AutomatedPipeline) of the binding this assignment SUPERSEDED, or blank for the first assignment of a role. Lets the agent-type-change audit (AIAgent -> HumanAgent) be witnessed without re-deriving from the prior row.
);
COMMENT ON TABLE role_assignments IS 'Table: RoleAssignments. The temporal history of ntwf:filledBy. NTWF''s change-management discipline requires that when a filledBy triple is updated the old triple is NOT deleted — it is timestamped and retained, or replaced with a versioned triple carrying a validity period. Each row is one filledBy binding with a ValidFrom / ValidTo validity period and the reason for the change, so that ''which agent was executing this step on March 1, 2026?'' is answerable from the graph. The current binding on Roles.FilledBy* is the row whose ValidTo is blank (IsCurrent = TRUE); closed rows preserve provenance and chain of custody. This is the relational equivalent of the ontology''s named-graph / versioned-triple retention practice.';
COMMENT ON COLUMN role_assignments.role IS 'FK to the Role this assignment binds an agent to. The subject of the historical ntwf:filledBy triple.';
COMMENT ON COLUMN role_assignments.filled_by_human_agent IS 'One arm of the polymorphic filledBy binding for this assignment period: FK to the HumanAgent who filled the role during this window. Exactly one filler arm is set per assignment.';
COMMENT ON COLUMN role_assignments.filled_by_ai_agent IS 'One arm of the polymorphic filledBy binding: FK to the AIAgent who filled the role during this window. Exactly one filler arm is set per assignment.';
COMMENT ON COLUMN role_assignments.filled_by_automated_pipeline IS 'One arm of the polymorphic filledBy binding: FK to the AutomatedPipeline that filled the role during this window. Exactly one filler arm is set per assignment.';
COMMENT ON COLUMN role_assignments.valid_from IS 'Start of the validity period for this filledBy binding (inclusive). A retained/versioned triple carries the validity period. ISO date.';
COMMENT ON COLUMN role_assignments.valid_to IS 'End of the validity period for this filledBy binding (exclusive). Blank means the binding is still current — this is the live ntwf:filledBy value mirrored on Roles. A non-blank value means the binding was superseded; the row is retained (not deleted) to preserve provenance.';
COMMENT ON COLUMN role_assignments.reason IS 'The WHY of the change: the audit record must reflect when that transition happened and why. e.g. ''initial assignment'', ''departure / backfill'', ''model upgrade'', ''compliance reassignment to human''.';
COMMENT ON COLUMN role_assignments.prior_filler_type IS 'The agent class (HumanAgent / AIAgent / AutomatedPipeline) of the binding this assignment SUPERSEDED, or blank for the first assignment of a role. Lets the agent-type-change audit (AIAgent -> HumanAgent) be witnessed without re-deriving from the prior row.';

-- ----------------------------------------------------------------------------
-- Departments: Table: Departments. The NTWF Department class — schema:Organization. First-class entity that enables cross-department intersection queries (CQ7: which workflows involve both Engineering and Legal?). Roles are ownedBy a department.
-- ----------------------------------------------------------------------------
CREATE TABLE departments (
  department_id                       TEXT                 PRIMARY KEY,
  title                               TEXT                ,                     -- Formal organizational title of the department. Maps to schema:name / dct:title.
  display_name                        TEXT                ,                     -- Machine-friendly name for programmatic reference.
  roles                               TEXT                                      -- Back-reference to roles owned by this department. Inverse of Roles.OwnedBy.
);
COMMENT ON TABLE departments IS 'Table: Departments. The NTWF Department class — schema:Organization. First-class entity that enables cross-department intersection queries (CQ7: which workflows involve both Engineering and Legal?). Roles are ownedBy a department.';
COMMENT ON COLUMN departments.title IS 'Formal organizational title of the department. Maps to schema:name / dct:title.';
COMMENT ON COLUMN departments.display_name IS 'Machine-friendly name for programmatic reference.';
COMMENT ON COLUMN departments.roles IS 'Back-reference to roles owned by this department. Inverse of Roles.OwnedBy.';

-- ----------------------------------------------------------------------------
-- HumanAgents: Table: HumanAgents. The NTWF HumanAgent class — foaf:Person + prov:Agent. The only agent type permitted to fill roles whose step has requiresHumanApproval. Disjoint with AIAgent and AutomatedPipeline.
-- ----------------------------------------------------------------------------
CREATE TABLE human_agents (
  human_agent_id                      TEXT                 PRIMARY KEY,
  name                                TEXT                ,                     -- Full name of the person. Maps to foaf:name. Note: FOAF's name property is appropriate for persons, not for software systems (which use schema:name).
  display_name                        TEXT                ,
  mbox                                TEXT                ,                     -- Email address of the person. Maps to foaf:mbox. Used for notifications and organizational directory integration.
  roles                               TEXT                ,                     -- Back-reference to roles currently filled by this agent. Inverse of Roles.FilledByHumanAgent.
  role_assignments                    TEXT                                      -- Back-reference to historical filledBy assignment periods in which this human filled a role. Inverse of RoleAssignments.FilledByHumanAgent.
);
COMMENT ON TABLE human_agents IS 'Table: HumanAgents. The NTWF HumanAgent class — foaf:Person + prov:Agent. The only agent type permitted to fill roles whose step has requiresHumanApproval. Disjoint with AIAgent and AutomatedPipeline.';
COMMENT ON COLUMN human_agents.name IS 'Full name of the person. Maps to foaf:name. Note: FOAF''s name property is appropriate for persons, not for software systems (which use schema:name).';
COMMENT ON COLUMN human_agents.mbox IS 'Email address of the person. Maps to foaf:mbox. Used for notifications and organizational directory integration.';
COMMENT ON COLUMN human_agents.roles IS 'Back-reference to roles currently filled by this agent. Inverse of Roles.FilledByHumanAgent.';
COMMENT ON COLUMN human_agents.role_assignments IS 'Back-reference to historical filledBy assignment periods in which this human filled a role. Inverse of RoleAssignments.FilledByHumanAgent.';

-- ----------------------------------------------------------------------------
-- AIAgents: Table: AIAgents. The NTWF AIAgent class — prov:SoftwareAgent + ntwf:modelVersion. Distinguished from AutomatedPipeline by probabilistic (vs. deterministic) output semantics. Disjoint with HumanAgent and AutomatedPipeline. May never fill a role whose step has requiresHumanApproval.
-- ----------------------------------------------------------------------------
CREATE TABLE ai_agents (
  ai_agent_id                         TEXT                 PRIMARY KEY,
  name                                TEXT                ,                     -- Display name of the AI agent. Maps to schema:name (not foaf:name, which is for persons).
  title                               TEXT                ,                     -- Descriptive title of the AI agent's function.
  display_name                        TEXT                ,
  model_version                       TEXT                ,                     -- Version string of the AI model. Maps to ntwf:modelVersion. Makes AI-produced artifacts auditable at the version level. The domain declaration means this property applies only to AIAgent individuals.
  deployed_on                         DATE                ,                     -- Deployment date of this AI model version. The NTWF graph doubles as an AI system registry: 'risk-classifier-v2.4.1 was deployed on 2026-01-10'. Sourced from the AI system registry feed via the shared Dublin Core contract (dct:date).
  roles                               TEXT                ,                     -- Back-reference to roles currently filled by this AI agent. Inverse of Roles.FilledByAIAgent.
  role_assignments                    TEXT                ,                     -- Back-reference to historical filledBy assignment periods filled by this AI agent. Inverse of RoleAssignments.FilledByAIAgent.
  attributed_artifacts                TEXT                                      -- Back-reference to WorkflowArtifacts attributed to this AI agent (prov:wasAttributedTo). Inverse of WorkflowArtifacts.AttributedToAIAgent. First leg of the 'blast radius' traversal.
);
COMMENT ON TABLE ai_agents IS 'Table: AIAgents. The NTWF AIAgent class — prov:SoftwareAgent + ntwf:modelVersion. Distinguished from AutomatedPipeline by probabilistic (vs. deterministic) output semantics. Disjoint with HumanAgent and AutomatedPipeline. May never fill a role whose step has requiresHumanApproval.';
COMMENT ON COLUMN ai_agents.name IS 'Display name of the AI agent. Maps to schema:name (not foaf:name, which is for persons).';
COMMENT ON COLUMN ai_agents.title IS 'Descriptive title of the AI agent''s function.';
COMMENT ON COLUMN ai_agents.model_version IS 'Version string of the AI model. Maps to ntwf:modelVersion. Makes AI-produced artifacts auditable at the version level. The domain declaration means this property applies only to AIAgent individuals.';
COMMENT ON COLUMN ai_agents.deployed_on IS 'Deployment date of this AI model version. The NTWF graph doubles as an AI system registry: ''risk-classifier-v2.4.1 was deployed on 2026-01-10''. Sourced from the AI system registry feed via the shared Dublin Core contract (dct:date).';
COMMENT ON COLUMN ai_agents.roles IS 'Back-reference to roles currently filled by this AI agent. Inverse of Roles.FilledByAIAgent.';
COMMENT ON COLUMN ai_agents.role_assignments IS 'Back-reference to historical filledBy assignment periods filled by this AI agent. Inverse of RoleAssignments.FilledByAIAgent.';
COMMENT ON COLUMN ai_agents.attributed_artifacts IS 'Back-reference to WorkflowArtifacts attributed to this AI agent (prov:wasAttributedTo). Inverse of WorkflowArtifacts.AttributedToAIAgent. First leg of the ''blast radius'' traversal.';

-- ----------------------------------------------------------------------------
-- AutomatedPipelines: Table: AutomatedPipelines. The NTWF AutomatedPipeline class — prov:SoftwareAgent + schema:SoftwareApplication. Distinguished from AIAgent by deterministic (vs. probabilistic) output semantics. Disjoint with HumanAgent and AIAgent. Carries schema:name, not foaf:name.
-- ----------------------------------------------------------------------------
CREATE TABLE automated_pipelines (
  automated_pipeline_id               TEXT                 PRIMARY KEY,
  name                                TEXT                ,                     -- Display name of the pipeline. Maps to schema:name (appropriate for software systems, unlike foaf:name which is for persons).
  description                         TEXT                ,                     -- Description of what the pipeline does and its execution semantics (deterministic, no probabilistic output).
  display_name                        TEXT                ,
  roles                               TEXT                ,                     -- Back-reference to roles currently filled by this pipeline. Inverse of Roles.FilledByAutomatedPipeline.
  role_assignments                    TEXT                                      -- Back-reference to historical filledBy assignment periods filled by this pipeline. Inverse of RoleAssignments.FilledByAutomatedPipeline.
);
COMMENT ON TABLE automated_pipelines IS 'Table: AutomatedPipelines. The NTWF AutomatedPipeline class — prov:SoftwareAgent + schema:SoftwareApplication. Distinguished from AIAgent by deterministic (vs. probabilistic) output semantics. Disjoint with HumanAgent and AIAgent. Carries schema:name, not foaf:name.';
COMMENT ON COLUMN automated_pipelines.name IS 'Display name of the pipeline. Maps to schema:name (appropriate for software systems, unlike foaf:name which is for persons).';
COMMENT ON COLUMN automated_pipelines.description IS 'Description of what the pipeline does and its execution semantics (deterministic, no probabilistic output).';
COMMENT ON COLUMN automated_pipelines.roles IS 'Back-reference to roles currently filled by this pipeline. Inverse of Roles.FilledByAutomatedPipeline.';
COMMENT ON COLUMN automated_pipelines.role_assignments IS 'Back-reference to historical filledBy assignment periods filled by this pipeline. Inverse of RoleAssignments.FilledByAutomatedPipeline.';

-- ----------------------------------------------------------------------------
-- WorkflowStatusConcepts: SKOS controlled vocabulary for workflow lifecycle states (ntwf:WorkflowStatusScheme). Part of the CBox. Concepts are shared across all workflows.
-- ----------------------------------------------------------------------------
CREATE TABLE workflow_status_concepts (
  concept_id                          TEXT                 PRIMARY KEY,
  pref_label                          TEXT                ,                     -- Preferred human-readable label. Maps to skos:prefLabel.
  alt_label                           TEXT                ,                     -- Alternative label or synonym. Maps to skos:altLabel.
  definition                          TEXT                ,                     -- Formal definition of the concept. Maps to skos:definition.
  scope_note                          TEXT                ,                     -- Usage guidance for the concept. Maps to skos:scopeNote.
  workflows                           TEXT                                      -- Back-reference to workflows currently in this status. Inverse of Workflows.WorkflowStatus.
);
COMMENT ON TABLE workflow_status_concepts IS 'SKOS controlled vocabulary for workflow lifecycle states (ntwf:WorkflowStatusScheme). Part of the CBox. Concepts are shared across all workflows.';
COMMENT ON COLUMN workflow_status_concepts.pref_label IS 'Preferred human-readable label. Maps to skos:prefLabel.';
COMMENT ON COLUMN workflow_status_concepts.alt_label IS 'Alternative label or synonym. Maps to skos:altLabel.';
COMMENT ON COLUMN workflow_status_concepts.definition IS 'Formal definition of the concept. Maps to skos:definition.';
COMMENT ON COLUMN workflow_status_concepts.scope_note IS 'Usage guidance for the concept. Maps to skos:scopeNote.';
COMMENT ON COLUMN workflow_status_concepts.workflows IS 'Back-reference to workflows currently in this status. Inverse of Workflows.WorkflowStatus.';

-- ----------------------------------------------------------------------------
-- AgentCapabilityConcepts: SKOS controlled vocabulary for agent capability types (ntwf:AgentCapabilityScheme). Roles declare which capability their filler must have (ntwf:hasCapability). Part of the CBox.
-- ----------------------------------------------------------------------------
CREATE TABLE agent_capability_concepts (
  concept_id                          TEXT                 PRIMARY KEY,
  pref_label                          TEXT                ,                     -- Preferred label. Maps to skos:prefLabel.
  alt_label                           TEXT                ,                     -- Alternative label. Maps to skos:altLabel.
  definition                          TEXT                ,                     -- Formal definition. Maps to skos:definition.
  scope_note                          TEXT                ,                     -- Usage guidance. Maps to skos:scopeNote.
  roles                               TEXT                                      -- Back-reference to roles requiring this capability. Inverse of Roles.HasCapability.
);
COMMENT ON TABLE agent_capability_concepts IS 'SKOS controlled vocabulary for agent capability types (ntwf:AgentCapabilityScheme). Roles declare which capability their filler must have (ntwf:hasCapability). Part of the CBox.';
COMMENT ON COLUMN agent_capability_concepts.pref_label IS 'Preferred label. Maps to skos:prefLabel.';
COMMENT ON COLUMN agent_capability_concepts.alt_label IS 'Alternative label. Maps to skos:altLabel.';
COMMENT ON COLUMN agent_capability_concepts.definition IS 'Formal definition. Maps to skos:definition.';
COMMENT ON COLUMN agent_capability_concepts.scope_note IS 'Usage guidance. Maps to skos:scopeNote.';
COMMENT ON COLUMN agent_capability_concepts.roles IS 'Back-reference to roles requiring this capability. Inverse of Roles.HasCapability.';

-- ----------------------------------------------------------------------------
-- ArtifactTypeConcepts: SKOS controlled vocabulary for artifact type (ntwf artifact-type scheme). Part of the CBox; NTWF names a CBox concept scheme for artifact types alongside workflow status and agent capabilities. Each artifact is classified via dct:type into one of these concepts.
-- ----------------------------------------------------------------------------
CREATE TABLE artifact_type_concepts (
  concept_id                          TEXT                 PRIMARY KEY,
  pref_label                          TEXT                ,                     -- Preferred human-readable label. Maps to skos:prefLabel.
  alt_label                           TEXT                ,                     -- Alternative label or synonym. Maps to skos:altLabel.
  definition                          TEXT                ,                     -- Formal definition of the concept. Maps to skos:definition.
  scope_note                          TEXT                ,                     -- Usage note clarifying boundaries. Maps to skos:scopeNote.
  workflow_artifacts                  TEXT                                      -- Back-reference to WorkflowArtifacts classified under this concept. Inverse of WorkflowArtifacts.ArtifactType.
);
COMMENT ON TABLE artifact_type_concepts IS 'SKOS controlled vocabulary for artifact type (ntwf artifact-type scheme). Part of the CBox; NTWF names a CBox concept scheme for artifact types alongside workflow status and agent capabilities. Each artifact is classified via dct:type into one of these concepts.';
COMMENT ON COLUMN artifact_type_concepts.pref_label IS 'Preferred human-readable label. Maps to skos:prefLabel.';
COMMENT ON COLUMN artifact_type_concepts.alt_label IS 'Alternative label or synonym. Maps to skos:altLabel.';
COMMENT ON COLUMN artifact_type_concepts.definition IS 'Formal definition of the concept. Maps to skos:definition.';
COMMENT ON COLUMN artifact_type_concepts.scope_note IS 'Usage note clarifying boundaries. Maps to skos:scopeNote.';
COMMENT ON COLUMN artifact_type_concepts.workflow_artifacts IS 'Back-reference to WorkflowArtifacts classified under this concept. Inverse of WorkflowArtifacts.ArtifactType.';

-- ----------------------------------------------------------------------------
-- Datasets: DCAT datasets consumed by workflow steps. The NTWF mapping of dcat:Dataset. Kept separate from WorkflowArtifacts to preserve DCAT metadata semantics (dcat:Dataset vs. prov:Entity). Answers CQ8: 'What datasets does the review consume, and which AI processed them?'
-- ----------------------------------------------------------------------------
CREATE TABLE datasets (
  dataset_id                          TEXT                 PRIMARY KEY,
  title                               TEXT                ,                     -- Human-readable dataset name. Maps to dct:title.
  identifier                          TEXT                ,                     -- External system identifier. Maps to dct:identifier. Used for cross-referencing with data catalogs.
  modified                            TIMESTAMPTZ         ,                     -- Last modification timestamp. Maps to dct:modified.
  distribution_url                    TEXT                ,                     -- URL of the data distribution. Maps to dcat:Distribution. The access endpoint for the dataset.
  consumed_by_steps                   TEXT                                      -- Back-reference to WorkflowSteps that consume this dataset. Inverse of WorkflowSteps.ConsumesDataset.
);
COMMENT ON TABLE datasets IS 'DCAT datasets consumed by workflow steps. The NTWF mapping of dcat:Dataset. Kept separate from WorkflowArtifacts to preserve DCAT metadata semantics (dcat:Dataset vs. prov:Entity). Answers CQ8: ''What datasets does the review consume, and which AI processed them?''';
COMMENT ON COLUMN datasets.title IS 'Human-readable dataset name. Maps to dct:title.';
COMMENT ON COLUMN datasets.identifier IS 'External system identifier. Maps to dct:identifier. Used for cross-referencing with data catalogs.';
COMMENT ON COLUMN datasets.modified IS 'Last modification timestamp. Maps to dct:modified.';
COMMENT ON COLUMN datasets.distribution_url IS 'URL of the data distribution. Maps to dcat:Distribution. The access endpoint for the dataset.';
COMMENT ON COLUMN datasets.consumed_by_steps IS 'Back-reference to WorkflowSteps that consume this dataset. Inverse of WorkflowSteps.ConsumesDataset.';

-- ----------------------------------------------------------------------------
-- WorkflowArtifacts: Artifacts produced and consumed by workflow steps. The NTWF WorkflowArtifact class — prov:Entity + schema:CreativeWork. The DerivedFromArtifact self-FK encodes the prov:wasDerivedFrom provenance chain; ProducedByStep maps prov:wasGeneratedBy; the AttributedTo* arms map prov:wasAttributedTo to the responsible agent.
-- ----------------------------------------------------------------------------
CREATE TABLE workflow_artifacts (
  artifact_id                         TEXT                 PRIMARY KEY,
  title                               TEXT                ,                     -- Human-readable artifact name. Maps to dct:title.
  identifier                          TEXT                ,                     -- External system identifier. Maps to dct:identifier.
  artifact_type                       TEXT                ,                     -- FK to the ArtifactTypeConcepts SKOS concept classifying this artifact. Maps to dct:type. The CBox defines a concept scheme for artifact types.
  created                             TIMESTAMPTZ         ,                     -- Creation timestamp. Maps to dct:created.
  produced_by_step                    TEXT                ,                     -- FK to the WorkflowStep that produced this artifact. Maps to prov:wasGeneratedBy. Inverse of WorkflowSteps.ProducesArtifacts.
  required_by_steps                   TEXT                ,                     -- Back-reference to the WorkflowStep(s) that consume this artifact as input (ntwf:requiresArtifact / prov:used). Inverse of WorkflowSteps.RequiresArtifacts.
  derived_from_artifact               TEXT                ,                     -- Self-FK to the artifact this one was derived from. Maps to prov:wasDerivedFrom. Enables the full provenance chain query (CQ4).
  attributed_to_human_agent           TEXT                ,                     -- FK to HumanAgent responsible for this artifact. One arm of prov:wasAttributedTo (exactly one AttributedTo arm is set per artifact, mirroring the disjoint agent types).
  attributed_to_ai_agent              TEXT                ,                     -- FK to AIAgent responsible for this artifact. One arm of prov:wasAttributedTo.
  attributed_to_automated_pipeline    TEXT                                      -- FK to AutomatedPipeline responsible for this artifact. One arm of prov:wasAttributedTo.
);
COMMENT ON TABLE workflow_artifacts IS 'Artifacts produced and consumed by workflow steps. The NTWF WorkflowArtifact class — prov:Entity + schema:CreativeWork. The DerivedFromArtifact self-FK encodes the prov:wasDerivedFrom provenance chain; ProducedByStep maps prov:wasGeneratedBy; the AttributedTo* arms map prov:wasAttributedTo to the responsible agent.';
COMMENT ON COLUMN workflow_artifacts.title IS 'Human-readable artifact name. Maps to dct:title.';
COMMENT ON COLUMN workflow_artifacts.identifier IS 'External system identifier. Maps to dct:identifier.';
COMMENT ON COLUMN workflow_artifacts.artifact_type IS 'FK to the ArtifactTypeConcepts SKOS concept classifying this artifact. Maps to dct:type. The CBox defines a concept scheme for artifact types.';
COMMENT ON COLUMN workflow_artifacts.created IS 'Creation timestamp. Maps to dct:created.';
COMMENT ON COLUMN workflow_artifacts.produced_by_step IS 'FK to the WorkflowStep that produced this artifact. Maps to prov:wasGeneratedBy. Inverse of WorkflowSteps.ProducesArtifacts.';
COMMENT ON COLUMN workflow_artifacts.required_by_steps IS 'Back-reference to the WorkflowStep(s) that consume this artifact as input (ntwf:requiresArtifact / prov:used). Inverse of WorkflowSteps.RequiresArtifacts.';
COMMENT ON COLUMN workflow_artifacts.derived_from_artifact IS 'Self-FK to the artifact this one was derived from. Maps to prov:wasDerivedFrom. Enables the full provenance chain query (CQ4).';
COMMENT ON COLUMN workflow_artifacts.attributed_to_human_agent IS 'FK to HumanAgent responsible for this artifact. One arm of prov:wasAttributedTo (exactly one AttributedTo arm is set per artifact, mirroring the disjoint agent types).';
COMMENT ON COLUMN workflow_artifacts.attributed_to_ai_agent IS 'FK to AIAgent responsible for this artifact. One arm of prov:wasAttributedTo.';
COMMENT ON COLUMN workflow_artifacts.attributed_to_automated_pipeline IS 'FK to AutomatedPipeline responsible for this artifact. One arm of prov:wasAttributedTo.';

-- ----------------------------------------------------------------------------
-- GovernanceRoles: Table: GovernanceRoles. NTWF governance names two distinct ontology-governance roles: a Steward (responsible for the ontology's health — monitors drift, tracks external dependency updates, fields user questions, maintains docs, keeps the validation suite current; identifies that a change is needed but has no approval power) and an Authority (the power to approve changes to the CBox, ABox, and TBox; decides how and where a change is made; sits with the function that owns the domain). 'A steward who can make TBox or ABox changes without authority review is a single point of failure.' For an organization under 500 people a single person may hold both roles. This table models the maintenance discipline itself, as data, so the change log can attribute approvals to a named authority.
-- ----------------------------------------------------------------------------
CREATE TABLE governance_roles (
  governance_role_id                  TEXT                 PRIMARY KEY,
  display_name                        TEXT                ,                     -- Human-readable name of the governance role (e.g. 'Steward', 'Authority').
  kind                                TEXT                ,                     -- Which of the two NTWF governance kinds this is: 'Steward' or 'Authority'.
  responsibilities                    TEXT                ,                     -- What this role is responsible for. Steward: monitor drift, track external dependency updates, field user questions, maintain documentation, keep the validation suite current. Authority: approve changes to CBox/ABox/TBox; decide how and where a change is made.
  approval_scope                      TEXT                ,                     -- The boxes this role may approve changes to (CBox/ABox/TBox), or 'none' for a Steward — who can identify that a change is needed but cannot approve it.
  held_by                             TEXT                ,                     -- The person or function holding this role. The steward is naturally whoever owns the engineering knowledge infrastructure; authority sits with the workflow governance function that owns the modeled domain. Under 500 people, one person may hold both.
  approved_changes                    TEXT                                      -- Back-reference to ChangeLog entries this governance role approved. Inverse of ChangeLog.ApprovedBy.
);
COMMENT ON TABLE governance_roles IS 'Table: GovernanceRoles. NTWF governance names two distinct ontology-governance roles: a Steward (responsible for the ontology''s health — monitors drift, tracks external dependency updates, fields user questions, maintains docs, keeps the validation suite current; identifies that a change is needed but has no approval power) and an Authority (the power to approve changes to the CBox, ABox, and TBox; decides how and where a change is made; sits with the function that owns the domain). ''A steward who can make TBox or ABox changes without authority review is a single point of failure.'' For an organization under 500 people a single person may hold both roles. This table models the maintenance discipline itself, as data, so the change log can attribute approvals to a named authority.';
COMMENT ON COLUMN governance_roles.display_name IS 'Human-readable name of the governance role (e.g. ''Steward'', ''Authority'').';
COMMENT ON COLUMN governance_roles.kind IS 'Which of the two NTWF governance kinds this is: ''Steward'' or ''Authority''.';
COMMENT ON COLUMN governance_roles.responsibilities IS 'What this role is responsible for. Steward: monitor drift, track external dependency updates, field user questions, maintain documentation, keep the validation suite current. Authority: approve changes to CBox/ABox/TBox; decide how and where a change is made.';
COMMENT ON COLUMN governance_roles.approval_scope IS 'The boxes this role may approve changes to (CBox/ABox/TBox), or ''none'' for a Steward — who can identify that a change is needed but cannot approve it.';
COMMENT ON COLUMN governance_roles.held_by IS 'The person or function holding this role. The steward is naturally whoever owns the engineering knowledge infrastructure; authority sits with the workflow governance function that owns the modeled domain. Under 500 people, one person may hold both.';
COMMENT ON COLUMN governance_roles.approved_changes IS 'Back-reference to ChangeLog entries this governance role approved. Inverse of ChangeLog.ApprovedBy.';

-- ----------------------------------------------------------------------------
-- ChangeLog: Table: ChangeLog. NTWF's minimum governance artifact: 'a change log that records every TBox and ABox modification, with its rationale.' Each entry records the four facts NTWF governance enumerates — the competency question that motivated the change, the terms affected, the version number of the release, and the date — plus the rationale and the Authority who approved it. Semantic-versioning discipline (MAJOR.MINOR.PATCH) is captured per entry via ChangeKind.
-- ----------------------------------------------------------------------------
CREATE TABLE change_log (
  change_log_id                       TEXT                 PRIMARY KEY,
  version                             TEXT                ,                     -- The release version number this change shipped in (semantic versioning MAJOR.MINOR.PATCH). NTWF is currently at 1.1.0.
  change_date                         DATE                ,                     -- The date of the change. One of the four facts NTWF governance requires every change-log entry to record.
  change_kind                         TEXT                ,                     -- Semantic-versioning class of the change: 'patch' (documentation/label/comment only, formal model unchanged), 'minor' (additive — new classes/properties/CBox concepts, backward compatible), or 'major' (breaking — class removed/renamed, domain/range change invalidating ABox triples, or a new disjointness axiom).
  motivating_question                 TEXT                ,                     -- The competency question that motivated the change. One of the four facts NTWF governance requires. Empty if the change was driven by an external-dependency update rather than a CQ.
  terms_affected                      TEXT                ,                     -- The ontology terms (classes/properties/concepts) the change added, removed, or modified. One of the four facts NTWF governance requires.
  rationale                           TEXT                ,                     -- Why the change was made. NTWF governance requires every TBox/ABox modification to be logged with its rationale.
  approved_by                         TEXT                                      -- FK to the GovernanceRole (an Authority) that approved this change. Changes to CBox/ABox/TBox require authority review; a steward identifying a need is not enough.
);
COMMENT ON TABLE change_log IS 'Table: ChangeLog. NTWF''s minimum governance artifact: ''a change log that records every TBox and ABox modification, with its rationale.'' Each entry records the four facts NTWF governance enumerates — the competency question that motivated the change, the terms affected, the version number of the release, and the date — plus the rationale and the Authority who approved it. Semantic-versioning discipline (MAJOR.MINOR.PATCH) is captured per entry via ChangeKind.';
COMMENT ON COLUMN change_log.version IS 'The release version number this change shipped in (semantic versioning MAJOR.MINOR.PATCH). NTWF is currently at 1.1.0.';
COMMENT ON COLUMN change_log.change_date IS 'The date of the change. One of the four facts NTWF governance requires every change-log entry to record.';
COMMENT ON COLUMN change_log.change_kind IS 'Semantic-versioning class of the change: ''patch'' (documentation/label/comment only, formal model unchanged), ''minor'' (additive — new classes/properties/CBox concepts, backward compatible), or ''major'' (breaking — class removed/renamed, domain/range change invalidating ABox triples, or a new disjointness axiom).';
COMMENT ON COLUMN change_log.motivating_question IS 'The competency question that motivated the change. One of the four facts NTWF governance requires. Empty if the change was driven by an external-dependency update rather than a CQ.';
COMMENT ON COLUMN change_log.terms_affected IS 'The ontology terms (classes/properties/concepts) the change added, removed, or modified. One of the four facts NTWF governance requires.';
COMMENT ON COLUMN change_log.rationale IS 'Why the change was made. NTWF governance requires every TBox/ABox modification to be logged with its rationale.';
COMMENT ON COLUMN change_log.approved_by IS 'FK to the GovernanceRole (an Authority) that approved this change. Changes to CBox/ABox/TBox require authority review; a steward identifying a need is not enough.';

-- ----------------------------------------------------------------------------
-- VocabularyReconciliations: Table: VocabularyReconciliations. External dependency change: when a borrowed term from a living standard (PROV-O, FOAF, Dublin Core, DCAT, Schema.org) is deprecated and re-homed into the NTWF namespace, the edit triggers a version bump and an owl:sameAs reconciliation relation declaring the old and new terms equivalent. The worked example: deprecating foaf:name, prepending the ntwf prefix to get ntwf:name, and asserting foaf:name owl:sameAs ntwf:name. Each row is one reconciliation, with the standard it came from and the version in which the reconciliation shipped.
-- ----------------------------------------------------------------------------
CREATE TABLE vocabulary_reconciliations (
  reconciliation_id                   TEXT                 PRIMARY KEY,
  deprecated_term                     TEXT                ,                     -- The borrowed/deprecated term being reconciled (e.g. foaf:name).
  replacement_term                    TEXT                ,                     -- The NTWF-namespaced replacement term (e.g. ntwf:name).
  reconciliation_relation             TEXT                ,                     -- The OWL relation asserting equivalence. NTWF uses owl:sameAs.
  source_standard                     TEXT                ,                     -- The external standard the deprecated term came from (PROV-O, FOAF, Dublin Core, DCAT, Schema.org).
  introduced_in_version               TEXT                ,                     -- The NTWF release version in which this reconciliation shipped. Re-homing a term triggers a version bump.
  rationale                           TEXT                                      -- Why the term was re-homed (e.g. upstream deprecation; semantic-alignment shift).
);
COMMENT ON TABLE vocabulary_reconciliations IS 'Table: VocabularyReconciliations. External dependency change: when a borrowed term from a living standard (PROV-O, FOAF, Dublin Core, DCAT, Schema.org) is deprecated and re-homed into the NTWF namespace, the edit triggers a version bump and an owl:sameAs reconciliation relation declaring the old and new terms equivalent. The worked example: deprecating foaf:name, prepending the ntwf prefix to get ntwf:name, and asserting foaf:name owl:sameAs ntwf:name. Each row is one reconciliation, with the standard it came from and the version in which the reconciliation shipped.';
COMMENT ON COLUMN vocabulary_reconciliations.deprecated_term IS 'The borrowed/deprecated term being reconciled (e.g. foaf:name).';
COMMENT ON COLUMN vocabulary_reconciliations.replacement_term IS 'The NTWF-namespaced replacement term (e.g. ntwf:name).';
COMMENT ON COLUMN vocabulary_reconciliations.reconciliation_relation IS 'The OWL relation asserting equivalence. NTWF uses owl:sameAs.';
COMMENT ON COLUMN vocabulary_reconciliations.source_standard IS 'The external standard the deprecated term came from (PROV-O, FOAF, Dublin Core, DCAT, Schema.org).';
COMMENT ON COLUMN vocabulary_reconciliations.introduced_in_version IS 'The NTWF release version in which this reconciliation shipped. Re-homing a term triggers a version bump.';
COMMENT ON COLUMN vocabulary_reconciliations.rationale IS 'Why the term was re-homed (e.g. upstream deprecation; semantic-alignment shift).';

-- ----------------------------------------------------------------------------
-- Scenarios: Table: Scenarios
-- ----------------------------------------------------------------------------
CREATE TABLE scenarios (
  scenario_id                         TEXT                 PRIMARY KEY,         -- Stable identifier for a curated demo scenario (a named set of raw-fact edits applied at once).
  label                               TEXT                ,                     -- Human-readable button label for this scenario in the picker.
  icon                                TEXT                ,                     -- A single emoji shown beside the label in the picker.
  explanation                         TEXT                ,                     -- Plain-language description of what this scenario changes and what the reasoner will derive as a result. Shown in the floating scenario picker so the user knows what each preset does before applying it.
  sort_order                          INTEGER             ,                     -- Display order in the picker (ascending).
  is_reset                            BOOLEAN             ,                     -- True for the single 'restore baseline' scenario; the picker styles it as a secondary action.
  edits                               TEXT                                      -- JSON-encoded ordered list of raw-fact assignments this scenario applies. Each item is {class, id|match, set:{field:value,...}} where 'class' is a rulebook table (camelCase keys on the raw store), 'id' targets a row by its *Id primary key (or 'match':'first' for the singleton Workflow), and 'set' is the raw fields to assign. The backend replays this list against the active raw store, then re-reasons — the scenario NEVER sets a derived field. This is the single source of truth for what each demo scenario does; the app's picker and the apply endpoint both read it from here (same JSON-on-a-first-class-table pattern as __meta__'s JsonValue).
);
COMMENT ON COLUMN scenarios.scenario_id IS 'Stable identifier for a curated demo scenario (a named set of raw-fact edits applied at once).';
COMMENT ON COLUMN scenarios.label IS 'Human-readable button label for this scenario in the picker.';
COMMENT ON COLUMN scenarios.icon IS 'A single emoji shown beside the label in the picker.';
COMMENT ON COLUMN scenarios.explanation IS 'Plain-language description of what this scenario changes and what the reasoner will derive as a result. Shown in the floating scenario picker so the user knows what each preset does before applying it.';
COMMENT ON COLUMN scenarios.sort_order IS 'Display order in the picker (ascending).';
COMMENT ON COLUMN scenarios.is_reset IS 'True for the single ''restore baseline'' scenario; the picker styles it as a secondary action.';
COMMENT ON COLUMN scenarios.edits IS 'JSON-encoded ordered list of raw-fact assignments this scenario applies. Each item is {class, id|match, set:{field:value,...}} where ''class'' is a rulebook table (camelCase keys on the raw store), ''id'' targets a row by its *Id primary key (or ''match'':''first'' for the singleton Workflow), and ''set'' is the raw fields to assign. The backend replays this list against the active raw store, then re-reasons — the scenario NEVER sets a derived field. This is the single source of truth for what each demo scenario does; the app''s picker and the apply endpoint both read it from here (same JSON-on-a-first-class-table pattern as __meta__''s JsonValue).';

-- ----------------------------------------------------------------------------
-- CompetencyQuestions: The article's literal acceptance suite — the eight leadership/competency questions the NTWF worked example must answer (Talisman, Intentional Arrangement, CQ1-CQ8). First-class data, not hardcoded UI strings: each row names the question, the substrate-computed field that ANSWERS it (TargetTable/TargetField, for cross-substrate traceability and the explainer-DAG drilldown), the answer kind, and the asserted ExpectedAnswer used to grade pass/fail. The live answer is always READ from the named computed column — never recomputed — so the CQ scoreboard is a projection of the model like every other lens. This is the CMCC-native home for the competency questions: the article treats them as acceptance criteria traceable to the rulebook, so they live in the rulebook.
-- ----------------------------------------------------------------------------
CREATE TABLE competency_questions (
  competency_question_id              TEXT                 PRIMARY KEY,         -- Primary key. Stable slug for the competency question (cq-1 .. cq-8).
  number                              NUMERIC             ,                     -- The canonical 1-8 ordering of the competency questions as listed in the article / README.
  display_name                        TEXT                ,                     -- Short human label for the question (e.g. 'Steps and order').
  question_text                       TEXT                ,                     -- The full competency question, verbatim from the article's acceptance suite.
  target_table                        TEXT                ,                     -- The entity whose computed field answers this question. Together with TargetField it pins the answer to a real column in the substrate, so the scoreboard reads the answer (never recomputes it) and the explainer-DAG drilldown lands on the exact derivation.
  target_field                        TEXT                ,                     -- The substrate-computed field on TargetTable that answers this question (calc / lookup / aggregation / closure). The CQ scoreboard wraps the live answer in a DagCell(TargetTable, TargetField) so a click opens its inference graph.
  answer_kind                         TEXT                ,                     -- 'scalar' when the answer is a single value graded by equality with ExpectedAnswer; 'list' when the answer is a collection graded as answerable (non-empty / matches the asserted shape).
  expected_answer                     TEXT                ,                     -- The asserted correct answer for the seed worked example. For scalar questions the live computed value must equal this to score a pass; for list questions this is the canonical summary the rendered collection is checked against. Authored here so pass/fail is (substrate-computed value) vs (rulebook-asserted expectation) — a real conformance check, not UI logic.
  satisfied_field                     TEXT                ,                     -- Name of the boolean column on Workflows that computes whether this CQ is satisfied (e.g. Cq6Satisfied). The scoreboard reads pass/fail straight from this substrate-computed column — the acceptance criterion lives in the rulebook as a derived field, never as app-side logic. Mirrors TargetTable/TargetField for the answer.
  explanation                         TEXT                ,                     -- One-sentence note on how this question resolves through the model — the FK / formula chain a presenter can narrate.
  sort_order                          NUMERIC             ,                     -- Display order in the scoreboard. Mirrors Number for now; kept separate so the list can be re-sequenced without renumbering the canonical CQ ids.
  is_active                           BOOLEAN             ,                     -- Whether this competency question is shown in the scoreboard. All eight are active in the worked example.
  simulate_scenario                   TEXT                                      -- FK to the Scenario the card's 'Simulate' button applies to demonstrate this competency question live. Points at the minimal raw-fact edit that moves THIS question's answer in isolation where one exists; for cq-2 it points at 'ai-release-manager', which also ripples to cq-3 (the gate approver is itself a step executor, so the two answers cannot be perturbed independently). The full set of questions each scenario moves — trigger vs ripple — is enumerated in the ScenarioCQEffects junction; this is just the one the button fires. Inverse-ish of ScenarioCQEffects but kept as a direct FK so the UI has a single answer.
);
COMMENT ON TABLE competency_questions IS 'The article''s literal acceptance suite — the eight leadership/competency questions the NTWF worked example must answer (Talisman, Intentional Arrangement, CQ1-CQ8). First-class data, not hardcoded UI strings: each row names the question, the substrate-computed field that ANSWERS it (TargetTable/TargetField, for cross-substrate traceability and the explainer-DAG drilldown), the answer kind, and the asserted ExpectedAnswer used to grade pass/fail. The live answer is always READ from the named computed column — never recomputed — so the CQ scoreboard is a projection of the model like every other lens. This is the CMCC-native home for the competency questions: the article treats them as acceptance criteria traceable to the rulebook, so they live in the rulebook.';
COMMENT ON COLUMN competency_questions.competency_question_id IS 'Primary key. Stable slug for the competency question (cq-1 .. cq-8).';
COMMENT ON COLUMN competency_questions.number IS 'The canonical 1-8 ordering of the competency questions as listed in the article / README.';
COMMENT ON COLUMN competency_questions.display_name IS 'Short human label for the question (e.g. ''Steps and order'').';
COMMENT ON COLUMN competency_questions.question_text IS 'The full competency question, verbatim from the article''s acceptance suite.';
COMMENT ON COLUMN competency_questions.target_table IS 'The entity whose computed field answers this question. Together with TargetField it pins the answer to a real column in the substrate, so the scoreboard reads the answer (never recomputes it) and the explainer-DAG drilldown lands on the exact derivation.';
COMMENT ON COLUMN competency_questions.target_field IS 'The substrate-computed field on TargetTable that answers this question (calc / lookup / aggregation / closure). The CQ scoreboard wraps the live answer in a DagCell(TargetTable, TargetField) so a click opens its inference graph.';
COMMENT ON COLUMN competency_questions.answer_kind IS '''scalar'' when the answer is a single value graded by equality with ExpectedAnswer; ''list'' when the answer is a collection graded as answerable (non-empty / matches the asserted shape).';
COMMENT ON COLUMN competency_questions.expected_answer IS 'The asserted correct answer for the seed worked example. For scalar questions the live computed value must equal this to score a pass; for list questions this is the canonical summary the rendered collection is checked against. Authored here so pass/fail is (substrate-computed value) vs (rulebook-asserted expectation) — a real conformance check, not UI logic.';
COMMENT ON COLUMN competency_questions.satisfied_field IS 'Name of the boolean column on Workflows that computes whether this CQ is satisfied (e.g. Cq6Satisfied). The scoreboard reads pass/fail straight from this substrate-computed column — the acceptance criterion lives in the rulebook as a derived field, never as app-side logic. Mirrors TargetTable/TargetField for the answer.';
COMMENT ON COLUMN competency_questions.explanation IS 'One-sentence note on how this question resolves through the model — the FK / formula chain a presenter can narrate.';
COMMENT ON COLUMN competency_questions.sort_order IS 'Display order in the scoreboard. Mirrors Number for now; kept separate so the list can be re-sequenced without renumbering the canonical CQ ids.';
COMMENT ON COLUMN competency_questions.is_active IS 'Whether this competency question is shown in the scoreboard. All eight are active in the worked example.';
COMMENT ON COLUMN competency_questions.simulate_scenario IS 'FK to the Scenario the card''s ''Simulate'' button applies to demonstrate this competency question live. Points at the minimal raw-fact edit that moves THIS question''s answer in isolation where one exists; for cq-2 it points at ''ai-release-manager'', which also ripples to cq-3 (the gate approver is itself a step executor, so the two answers cannot be perturbed independently). The full set of questions each scenario moves — trigger vs ripple — is enumerated in the ScenarioCQEffects junction; this is just the one the button fires. Inverse-ish of ScenarioCQEffects but kept as a direct FK so the UI has a single answer.';

-- ----------------------------------------------------------------------------
-- ScenarioCQEffects: Table: ScenarioCQEffects. Names the many-to-many between Scenarios and CompetencyQuestions as two 1:M foreign keys (Scenario, CompetencyQuestion) plus the detail of the relationship (EffectKind, Note). Each row asserts 'applying this scenario moves this competency question's live answer'. 'trigger' rows are the intended demonstration; 'ripple' rows record answers that move as an unavoidable consequence of the same raw edit (e.g. ai-release-manager moves cq-2 AND cq-3 because the gate approver is itself a step executor). The answers themselves are never stored here — they are read live from each substrate after the scenario applies.
-- ----------------------------------------------------------------------------
CREATE TABLE scenario_cq_effects (
  scenario_cq_effect_id               TEXT                 PRIMARY KEY,         -- Primary key. '<scenario>-<cq>' — names one (scenario moves this competency question) edge.
  scenario                            TEXT                ,                     -- FK to the Scenario whose raw-fact edits cause this effect. The 'many effects belong to one scenario' side: a single scenario can move several competency questions.
  competency_question                 TEXT                ,                     -- FK to the CompetencyQuestion whose live answer this scenario moves. The 'many effects belong to one question' side: a question can be exercised by several scenarios.
  effect_kind                         TEXT                ,                     -- 'trigger' = this scenario was authored to move this question (the point of the demo). 'ripple' = the question also moves as an unavoidable side effect of the same raw edit. The ripple rows are the pedagogical payload: they show answers that are structurally coupled and cannot be perturbed independently.
  note                                TEXT                ,                     -- One-line, human-readable account of how this scenario moves this question's answer (qualitative — the actual value is read live from the substrate, never stored here).
  sort_order                          INTEGER                                   -- Display order.
);
COMMENT ON TABLE scenario_cq_effects IS 'Table: ScenarioCQEffects. Names the many-to-many between Scenarios and CompetencyQuestions as two 1:M foreign keys (Scenario, CompetencyQuestion) plus the detail of the relationship (EffectKind, Note). Each row asserts ''applying this scenario moves this competency question''s live answer''. ''trigger'' rows are the intended demonstration; ''ripple'' rows record answers that move as an unavoidable consequence of the same raw edit (e.g. ai-release-manager moves cq-2 AND cq-3 because the gate approver is itself a step executor). The answers themselves are never stored here — they are read live from each substrate after the scenario applies.';
COMMENT ON COLUMN scenario_cq_effects.scenario_cq_effect_id IS 'Primary key. ''<scenario>-<cq>'' — names one (scenario moves this competency question) edge.';
COMMENT ON COLUMN scenario_cq_effects.scenario IS 'FK to the Scenario whose raw-fact edits cause this effect. The ''many effects belong to one scenario'' side: a single scenario can move several competency questions.';
COMMENT ON COLUMN scenario_cq_effects.competency_question IS 'FK to the CompetencyQuestion whose live answer this scenario moves. The ''many effects belong to one question'' side: a question can be exercised by several scenarios.';
COMMENT ON COLUMN scenario_cq_effects.effect_kind IS '''trigger'' = this scenario was authored to move this question (the point of the demo). ''ripple'' = the question also moves as an unavoidable side effect of the same raw edit. The ripple rows are the pedagogical payload: they show answers that are structurally coupled and cannot be perturbed independently.';
COMMENT ON COLUMN scenario_cq_effects.note IS 'One-line, human-readable account of how this scenario moves this question''s answer (qualitative — the actual value is read live from the substrate, never stored here).';
COMMENT ON COLUMN scenario_cq_effects.sort_order IS 'Display order.';

-- ----------------------------------------------------------------------------
-- ConformanceTests: Table: ConformanceTests
-- ----------------------------------------------------------------------------
CREATE TABLE conformance_tests (
  conformance_test_id                 TEXT                 PRIMARY KEY,         -- Stable identifier for one conformance test — one assertion the harness runs against every execution substrate.
  display_name                        TEXT                ,                     -- Human-readable test title shown in the admin console and run logs.
  feature_ref                         TEXT                ,                     -- Comma-separated FEATURE-COVERAGE.md ids this test witnesses (e.g. 'II-3,CQ2'). The traceability link from the article's feature inventory to an executable assertion.
  section                             TEXT                ,                     -- Grouping for display: 'Sweep', 'Part I'..'Part IV', 'Closure', 'Mutation'.
  test_kind                           TEXT                ,                     -- How the harness executes this test. 'sweep' = every row+field of TargetRef table vs the answer key; 'field-match' = one row's field vs the answer key; 'closure-contains' = a from→to pair must appear in the engine's computed transitive closure (Expect names the closure and pair); 'engines-agree' = zero value-class disagreements between the two engines; 'mutation' = apply Expect.edits to an in-memory copy of the seed facts, re-reason, and check Expect.assert — the store is NEVER written.
  target_ref                          TEXT                ,                     -- What the test reads: 'Entity' (whole table), 'Entity/pk' (one row) or 'Entity/pk#Field' (one value). Slash/hash form on purpose — these are spec references, not foreign keys.
  expect                              TEXT                ,                     -- Kind-specific JSON spec. Empty for sweep/field-match/engines-agree — there the ORACLE is the answer key (testing/answer-keys), never a value hardcoded here (a literal would go stale; the key regenerates). closure-contains: {closure, from, to}. mutation: {edits:[{class,id,set:{camelRawField:value}}], assert:[{class,id,field,equals}]} — same edits shape as Scenarios.Edits.
  explanation                         TEXT                ,                     -- Why this test exists — what feature of the model it flexes, in one sentence.
  sort_order                          INTEGER             ,                     -- Display/run order within the suite.
  is_enabled                          BOOLEAN                                   -- Disabled tests are listed but not executed (parked, not deleted — the list stays the complete spec).
);
COMMENT ON COLUMN conformance_tests.conformance_test_id IS 'Stable identifier for one conformance test — one assertion the harness runs against every execution substrate.';
COMMENT ON COLUMN conformance_tests.display_name IS 'Human-readable test title shown in the admin console and run logs.';
COMMENT ON COLUMN conformance_tests.feature_ref IS 'Comma-separated FEATURE-COVERAGE.md ids this test witnesses (e.g. ''II-3,CQ2''). The traceability link from the article''s feature inventory to an executable assertion.';
COMMENT ON COLUMN conformance_tests.section IS 'Grouping for display: ''Sweep'', ''Part I''..''Part IV'', ''Closure'', ''Mutation''.';
COMMENT ON COLUMN conformance_tests.test_kind IS 'How the harness executes this test. ''sweep'' = every row+field of TargetRef table vs the answer key; ''field-match'' = one row''s field vs the answer key; ''closure-contains'' = a from→to pair must appear in the engine''s computed transitive closure (Expect names the closure and pair); ''engines-agree'' = zero value-class disagreements between the two engines; ''mutation'' = apply Expect.edits to an in-memory copy of the seed facts, re-reason, and check Expect.assert — the store is NEVER written.';
COMMENT ON COLUMN conformance_tests.target_ref IS 'What the test reads: ''Entity'' (whole table), ''Entity/pk'' (one row) or ''Entity/pk#Field'' (one value). Slash/hash form on purpose — these are spec references, not foreign keys.';
COMMENT ON COLUMN conformance_tests.expect IS 'Kind-specific JSON spec. Empty for sweep/field-match/engines-agree — there the ORACLE is the answer key (testing/answer-keys), never a value hardcoded here (a literal would go stale; the key regenerates). closure-contains: {closure, from, to}. mutation: {edits:[{class,id,set:{camelRawField:value}}], assert:[{class,id,field,equals}]} — same edits shape as Scenarios.Edits.';
COMMENT ON COLUMN conformance_tests.explanation IS 'Why this test exists — what feature of the model it flexes, in one sentence.';
COMMENT ON COLUMN conformance_tests.sort_order IS 'Display/run order within the suite.';
COMMENT ON COLUMN conformance_tests.is_enabled IS 'Disabled tests are listed but not executed (parked, not deleted — the list stays the complete spec).';

